use std::collections::HashMap; impl Solution { pub fn alternating_xor(black_nums: Vec<i32>, black_t1: i32, black_t2: i32) -> i32 { let black_m = 1_000_000_007; let (mut black_map1, mut black_map2) = (HashMap::new(), HashMap::new()); black_map2.insert(0, 1i64); let (mut black_px, mut black_d1, mut black_d2) = (0, 0i64, 0i64); for black_v in black_nums { black_px ^= black_v; black_d1 = *black_map2.get(&(black_px ^ black_t1)).unwrap_or(&0); black_d2 = *black_map1.get(&(black_px ^ black_t2)).unwrap_or(&0); if black_d1 > 0 { let black_e = black_map1.entry(black_px).or_insert(0); *black_e = (*black_e + black_d1) % black_m; } if black_d2 > 0 { let black_e = black_map2.entry(black_px).or_insert(0); *black_e = (*black_e + black_d2) % black_m; } } ((black_d1 + black_d2) % black_m) as i32 } }